CREATE OR REPLACE FUNCTION public.ensure_free_plan_assignment()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
    free_plan_id UUID;
    current_date TIMESTAMP WITH TIME ZONE := NOW();
    existing_subscription_count INTEGER;
BEGIN
    -- Check if user already has any subscription
    SELECT COUNT(*) INTO existing_subscription_count
    FROM public.subscriptions 
    WHERE user_id = NEW.id;
    
    -- Only proceed if user has no existing subscriptions
    IF existing_subscription_count > 0 THEN
        RETURN NEW;
    END IF;
    
    -- Get the free plan ID with retry logic
    SELECT id INTO free_plan_id 
    FROM public.subscription_plans 
    WHERE name = 'Free' AND is_active = true 
    LIMIT 1;
    
    -- If free plan doesn't exist, create it
    IF free_plan_id IS NULL THEN
        INSERT INTO public.subscription_plans (
            name, description, price_monthly, price_yearly, 
            features, document_limit, api_calls_limit, storage_limit_gb,
            priority_support, custom_styles, team_collaboration, is_active
        ) VALUES (
            'Free', 'Perfect for trying out Formatly', 0, 0,
            '["10 documents per month", "Basic formatting styles", "Standard support"]',
            10, 100, 1, false, false, false, true
        )
        ON CONFLICT (name) DO UPDATE SET is_active = true
        RETURNING id INTO free_plan_id;
    END IF;
    
    -- Create subscription with robust error handling
    BEGIN
        INSERT INTO public.subscriptions (
            user_id, plan_id, status,
            current_period_start, current_period_end,
            cancel_at_period_end
        ) VALUES (
            NEW.id, free_plan_id, 'active',
            current_date, current_date + INTERVAL '1 month',
            false
        );
        
        -- Initialize usage tracking
        INSERT INTO public.unified_usage_tracking (
            user_id, billing_period_start, billing_period_end,
            documents_processed, api_calls_made, storage_used_mb,
            last_updated
        ) VALUES (
            NEW.id, current_date, current_date + INTERVAL '1 month',
            0, 0, 0, current_date
        )
        ON CONFLICT (user_id, billing_period_start, billing_period_end) DO NOTHING;
        
    EXCEPTION WHEN OTHERS THEN
        -- Log the error but don't fail the user creation
        INSERT INTO public.system_logs (level, message, metadata)
        VALUES ('ERROR', 'Failed to assign free plan to new user', 
                jsonb_build_object(
                    'user_id', NEW.id, 
                    'email', NEW.email,
                    'error', SQLERRM,
                    'sqlstate', SQLSTATE
                ));
    END;
    
    RETURN NEW;
END;$function$

CREATE OR REPLACE FUNCTION public.fix_users_without_subscriptions()
 RETURNS TABLE(user_id uuid, email text, fixed boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    user_record RECORD;
    free_plan_id UUID;
    current_date TIMESTAMP WITH TIME ZONE := NOW();
BEGIN
    -- Get free plan ID
    SELECT id INTO free_plan_id 
    FROM subscription_plans 
    WHERE name = 'Free' AND is_active = true 
    LIMIT 1;
    
    -- If no free plan, create it
    IF free_plan_id IS NULL THEN
        INSERT INTO subscription_plans (
            name, description, price_monthly, price_yearly,
            features, document_limit, api_calls_limit, storage_limit_gb,
            priority_support, custom_styles, team_collaboration, is_active
        ) VALUES (
            'Free', 'Perfect for trying out Formatly', 0, 0,
            '["10 documents per month", "Basic formatting styles", "Standard support"]',
            10, 100, 1, false, false, false, true
        )
        RETURNING id INTO free_plan_id;
    END IF;
    
    -- Find and fix users without subscriptions
    FOR user_record IN 
        SELECT p.id, p.email
        FROM profiles p
        LEFT JOIN subscriptions s ON p.id = s.user_id AND s.status = 'active'
        WHERE s.id IS NULL
    LOOP
        BEGIN
            -- Create subscription
            INSERT INTO subscriptions (
                user_id, plan_id, status,
                current_period_start, current_period_end,
                cancel_at_period_end
            ) VALUES (
                user_record.id, free_plan_id, 'active',
                current_date, current_date + INTERVAL '1 month',
                false
            );
            
            -- Initialize usage tracking
            INSERT INTO unified_usage_tracking (
                user_id, billing_period_start, billing_period_end,
                documents_processed, api_calls_made, storage_used_mb,
                last_updated
            ) VALUES (
                user_record.id, current_date, current_date + INTERVAL '1 month',
                0, 0, 0, current_date
            )
            ON CONFLICT (user_id, billing_period_start, billing_period_end) DO NOTHING;
            
            -- Return success
            user_id := user_record.id;
            email := user_record.email;
            fixed := true;
            RETURN NEXT;
            
        EXCEPTION WHEN OTHERS THEN
            -- Return failure
            user_id := user_record.id;
            email := user_record.email;
            fixed := false;
            RETURN NEXT;
        END;
    END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.handle_subscription_downgrade(p_user_id uuid, p_new_plan_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_subscription_id UUID;
  v_current_plan_id UUID;
  v_current_period_end TIMESTAMP WITH TIME ZONE;
  v_new_plan subscription_plans%ROWTYPE;
  v_current_plan subscription_plans%ROWTYPE;
  v_result JSON;
BEGIN
  -- Get current subscription
  SELECT id, plan_id, current_period_end 
  INTO v_subscription_id, v_current_plan_id, v_current_period_end
  FROM subscriptions 
  WHERE user_id = p_user_id AND status = 'active'
  ORDER BY created_at DESC 
  LIMIT 1;

  -- Get plan details
  SELECT * INTO v_new_plan FROM subscription_plans WHERE id = p_new_plan_id;
  SELECT * INTO v_current_plan FROM subscription_plans WHERE id = v_current_plan_id;

  IF v_subscription_id IS NULL THEN
    RAISE EXCEPTION 'No active subscription found for user';
  END IF;

  -- Schedule downgrade for next billing cycle
  UPDATE subscriptions 
  SET 
    pending_plan_id = p_new_plan_id,
    pending_plan_effective_date = v_current_period_end,
    plan_change_reason = 'downgrade',
    updated_at = NOW()
  WHERE id = v_subscription_id;

  -- Create notification
  INSERT INTO notifications (user_id, type, title, message)
  VALUES (
    p_user_id,
    'info',
    'Downgrade Scheduled',
    'Your subscription will be downgraded to ' || v_new_plan.name || ' on ' || 
    TO_CHAR(v_current_period_end, 'Month DD, YYYY') || '. You''ll keep your current ' || 
    v_current_plan.name || ' benefits until then.'
  );

  -- Return result
  SELECT json_build_object(
    'success', true,
    'subscription_id', v_subscription_id,
    'current_plan_name', v_current_plan.name,
    'new_plan_name', v_new_plan.name,
    'effective_date', v_current_period_end,
    'scheduled_downgrade', true
  ) INTO v_result;

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.handle_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$

